INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-94737317-moex-00152', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「創業家集好奇心和勇氣於一身。他們天生好問，充滿好奇，同時勇於實踐自己的 想法，從失敗中學習。如果行不通，只需要刪除一個選項，永不重蹈覆轍就成了。 他們的心得是，如果你從未失敗，就表示你嘗試得不夠。聽說詹姆斯‧戴森試了五 千一百二十七個吸塵器的產品原型之後，才找到對的設計。每一次失敗，都讓他更 接近目標。」 根據上文，關於創業家的特質，下列敘述正確的是：', '["即使抱持強烈的好奇心，也不會輕易行事", "懂得從前人的成功之道，找到實踐的方法", "重蹈覆轍雖讓人受挫，但也累積更多經驗", "坦然面對每次失敗，相信這會更接近目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00153', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「Instagram 是一個全球流行的社交媒體平臺，許多人在這個平臺上分享了他們的 照片和影片，展示自己的成就，增強社交互動，接觸不同文化、擴大視野等。然而 Instagram 的內容可能讓人們產生身體自卑感，並且認為只有符合某種特定外表的 人才是美麗的，這種現象被稱為『Instagram效應』，此外，使用時也可能有成癮或 隱私的問題要注意，因此人們必須有效利用優點，並避免潛在的負面影響。」 根據上文，下列敘述何者正確？', '["使用Instagram的缺點大於優點，應該全面禁用", "在Instagram平臺上，人們往往追求美好形象而忽視了真實的自己", "Instagram上美化或修改過的照片，能讓人們自我感覺良好，增加社交自信心", "Instagram 能使人們更注意自己的體型和健康，因為人們總想分享較美或較好的 形象 90110"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00154', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '小說家海明威曾經提出冰山原則的寫作理論，他說：「講故事要像冰山一樣，只講 露出海面的八分之一，海面下的八分之七留給讀者想像。」 下列選項，何者不符合文意？', '["講故事的過程如果過於淺白直接，就會導致讀者缺乏想像的空間", "講故事的過程應該留下想像的空間，使讀者發揮抽象聯想的功力", "讀者在故事開頭的八分之一，就判斷是否要繼續讀後面八分之七", "讀者能從海面上的八分之一冰山，想像海面下那八分之七的世界"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00155', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「在實用性上，利用米的特質，如糯米的黏著性，可作為古蹟修復的傳統建築材料， 如磚牆的黏著，就是以糯米粉、黑糖、石灰混合作接著劑，其堅固性可作城牆、橋 梁。蓬萊米粉黏度適中的特性，是許多裱裝業者的黏著材料。釣客也會購買熟糯米 粉，以此作餌料的接著，可延遲入水後餌料四散的時間。」 根據上文，下列敘述何者錯誤？', '["米糧除了食用，還具實用性，從古蹟修復到釣魚人士都需要", "釣客可用熟糯米粉來接著餌料，入水後不易四散用以引誘魚", "裱裝業者選擇蓬萊米粉當黏著材料，是因為其黏度適合裱裝作品", "古蹟修復使用糯米粉用於黏著，加入黑糖混合則是增加香氣與美觀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00156', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「現代的閱聽人從被動接受訊息，到已能主動蒐集各式各樣的訊息，成為『主動閱 聽人』。當閱聽人選擇性蒐集又帶有偏見解讀新聞與訊息時，就已陷入認知偏差之 中。由於人性傾向於訴諸情感反應，於是假新聞瀰漫，真相已無關緊要，使得人們 活在『後真相』的時代。」 根據上文，下列選項何者正確？', '["被動的接受訊息能避免落入認知偏差的陷阱", "後真相時代讓閱聽人不容易受假新聞所影響", "對現代閱聽人來說，釐清真相是生活的日常", "假新聞因人性偏好，成為人們會相信的內容"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00157', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '智慧救災系統平板電腦的電池容量為8000mAh。如果平板電腦完全沒電後，使用功率為30W的快 速充電器，若以15V的定電壓來提供充電，則充滿平板電腦電池所需時間為何？', '["2小時", "4小時", "6小時", "8小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "76c106573e8e", "answer_pdf_sha1": "0584ea26d335", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00158', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '有關電學使用的單位，下列敘述何者正確？', '["智慧手機電池存儲的電荷以安培（ampere）為單位", "兩平行導線間的電位能以伏特（volt）為單位", "單位正電荷在平行板間移動的能量以庫倫（coulomb）為單位", "微波爐在工作時使用的功率以瓦特（watt）為單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "76c106573e8e", "answer_pdf_sha1": "0584ea26d335", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00159', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '下列那一個電力線（電場線）的圖示，可以表示正電荷q由P向Q作加速運動，且其加速度愈來 愈大？', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "76c106573e8e", "answer_pdf_sha1": "0584ea26d335", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00160', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '由實驗分析知道，均勻金屬線的電阻與長度有關。有關某一均勻金屬線的電阻，下列敘述何者正確？', '["電阻與長度成正比", "電阻與長度成反比", "電阻與長度2次方成正比", "電阻與長度2次方成反比"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "76c106573e8e", "answer_pdf_sha1": "0584ea26d335", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00161', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '在陰極射線管中，有一束電子自電子槍經由絲極與屏極間的電壓V 加速後射出，再經一對偏向金屬 1 板射達遠處螢幕（平行金屬板的長度遠小於與螢幕的距離），在螢幕上產生之偏移D為8.0厘米（如 圖所示）。若將絲極與屏極間之電位差V 加倍，而保持偏向金屬板間之電場不變，則偏移D為何？ 1 V 1 電子槍 金屬板 D 絲極 屏極', '["4.0厘米", "3.0厘米", "2.0厘米", "1.0厘米"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "76c106573e8e", "answer_pdf_sha1": "0584ea26d335", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
